public void writeObject(Object value) throws IOException
    {
            if (value == null) {
                writeNull();
                return;
            }
            if (_objectCodec != null) {
                _objectCodec.writeValue(this, value);
                return;
            }
            // If no codec, try JsonSerializable; otherwise embed as-is
            if (value instanceof com.fasterxml.jackson.core.JsonSerializable) {
                ((com.fasterxml.jackson.core.JsonSerializable) value).serialize(this, null);
                return;
            }
            _append(JsonToken.VALUE_EMBEDDED_OBJECT, value);
    }

public void writeTree(TreeNode node) throws IOException
    {
            if (node == null) {
                writeNull();
                return;
            }
            if (_objectCodec != null) {
                _objectCodec.writeTree(this, node);
                return;
            }
            // Without codec, embed the tree node as an object
            _append(JsonToken.VALUE_EMBEDDED_OBJECT, node);
    }
